(() => {
  const assets = {
    "background": "data:image/webp;base64,",
    "logo": "data:image/webp;base64,",
    "vocation-paladin": "data:image/webp;base64,",
    "vocation-sorcerer": "data:image/webp;base64,",
    "vocation-druid": "data:image/webp;base64,",
    "vocation-knight": "data:image/webp;base64,",
    "vocation-monk": "data:image/svg+xml;base64,",
  };
  const root = document.documentElement;
  root.style.setProperty("--asset-background", `url("${assets.background}")`);
  root.style.setProperty("--asset-vocation-paladin", `url("${assets["vocation-paladin"]}")`);
  root.style.setProperty("--asset-vocation-sorcerer", `url("${assets["vocation-sorcerer"]}")`);
  root.style.setProperty("--asset-vocation-druid", `url("${assets["vocation-druid"]}")`);
  root.style.setProperty("--asset-vocation-knight", `url("${assets["vocation-knight"]}")`);
  root.style.setProperty("--asset-vocation-monk", `url("${assets["vocation-monk"]}")`);
  const logo = document.querySelector("[data-brand-logo]");
  if (logo) logo.src = assets.logo;
})();
